  it('handles petOps.updateSettings through the pet ops RPC domain', async () => {
    let updatedSettings: unknown
    let currentSettings: PetSettings = {
      enabled: false,
      petId: 'bee',
      size: 'M',
      opacity: 1,
      hasHatched: false
    }
    const events: Array<{ channel: string; payload: unknown }> = []
    const eventBus = makeEventBus()
    const unsubscribe = Effect.runSync(
      eventBus.subscribeAll((event) => {
        events.push(event)
      })
    )
    const router = makeRpcRouter({
      eventBus,
      petOps: {
        show: () => Effect.succeed(undefined),
        hide: () => Effect.succeed(undefined),
        publishStatus: () => Effect.succeed(undefined),
        setIgnoreMouse: () => Effect.succeed(undefined),
        beginPointerInteraction: () => Effect.succeed(undefined),
        endPointerInteraction: () => Effect.succeed(undefined),
        move: () => Effect.succeed(undefined),
        focusMain: () => Effect.succeed(undefined),
        getConfig: () =>
          Effect.succeed({
            settings: currentSettings,
            position: { x: 42, y: 84 },
            manifest: {
              id: 'bee',
              name: 'Bee',
              version: '1.0.0',
              assets: {
                idle: 'assets/bee.png',
                working: 'assets/bee.png',
                question: 'assets/bee.png',
                permission: 'assets/bee.png',
                plan_ready: 'assets/bee.png'
              }
            }
          }),
        getCurrentStatus: () =>
          Effect.succeed({
            state: 'working' as const,
            sourceWorktreeId: 'worktree-1',
            workingSessionCount: 1
          }),
        updateSettings: (partial) =>
          Effect.sync(() => {
            updatedSettings = partial
            currentSettings = { ...currentSettings, ...partial }
          })
      }
    })

    const response = await Effect.runPromise(
      router.handle({
        id: 'pet-ops-update-settings-1',
        method: 'petOps.updateSettings',
        params: { enabled: true, size: 'L', opacity: 0.75 }
      })
    )

    expect(response).toEqual({
      id: 'pet-ops-update-settings-1',
      ok: true,
      value: undefined
    })
    expect(updatedSettings).toEqual({ enabled: true, size: 'L', opacity: 0.75 })
    expect(events).toEqual([{ channel: PET_SETTINGS_UPDATED_CHANNEL, payload: currentSettings }])
    unsubscribe()
  })

